external_knowledge:
- 'vr_co2_1st_order' represents the initial estimate of CO2 emissions from vegetation, serving as a foundational measurement for environmental studies;
- The metaphor of 'whispers of carbon' refers to the subtle and accumulating effects of CO2 emissions on the environment;
- The 'maze of time and geography' symbolically represents the complex interplay of historical data and spatial distribution in environmental science.

sql:
SELECT AVG(sv_co2_emission) AS average_emissions, MAX(sv_co2_emission) AS highest_emissions
FROM carbon_emissions
WHERE geographical_area = 'Amazon Rainforest';

SELECT year, geographical_area, sv_co2_emission
FROM carbon_emissions
WHERE year = 2000 AND geographical_area = 'Amazon Rainforest';

SELECT year 
FROM carbon_emissions 
WHERE net_co2_2nd_order = (SELECT MAX(net_co2_2nd_order) FROM carbon_emissions);

SELECT year, sv_area_cleared 
FROM vegetation_cover
WHERE year > 2000 AND sv_area_cleared > 10000;

SELECT geographical_area, last_updated
FROM carbon_emissions
WHERE year > 2000 AND confidence_level = 'High';

SELECT factor_id, COUNT(*) AS estimate_count
FROM emission_estimates
GROUP BY factor_id;

SELECT SUM(d_area) AS total_area
FROM carbon_emissions
WHERE geographical_area = 'Amazon Rainforest' AND year BETWEEN 2000 AND 2020;

SELECT co2_emission 
FROM emission_estimates 
WHERE factor_id = 1 AND data_source = 'Satellite';

SELECT AVG(co2_emission) AS average_co2_emission
FROM emission_estimates
WHERE year IN (2000, 2001) AND confidence_level = 'High';

external_knowledge:
- Turn of the century refers to the year 2000; 
- Secondary CO2 emissions are indicated by 'net second-order carbon dioxide emissions';
- Regions are referred to by 'geographical area'.

sql:
SELECT SUM(sv_co2_emission) AS total_co2_emissions
FROM carbon_emissions
WHERE year = 2000;

external_knowledge:
;
- Carbon dioxide emissions from fire are a subset of total emissions and are specifically estimated using a second-order method.
- Accumulated area over the years refers to the sum of areas covered in previous years, including the current year.

sql:
SELECT year, d_area, d_area_acc, vr_co2_2nd_order_fire AS total_co2_from_fire
FROM carbon_emissions
WHERE year = 2022;

SELECT "year", "sv_area_total"
FROM "vegetation_cover"
ORDER BY "year" ASC;

SELECT geographical_area, SUM(net_co2_2nd_order) AS total_net_co2_2nd_order
FROM carbon_emissions
GROUP BY geographical_area;

SELECT year, net_co2_2nd_order
FROM carbon_emissions
WHERE net_co2_2nd_order > (SELECT AVG(net_co2_2nd_order) FROM carbon_emissions);

